async ({ paginate }) => {
	const allPosts = await getAllPosts();
	const sortedPosts = allPosts.sort(collectionDateSort);
	const uniqueTags = getUniqueTags(sortedPosts);

	return uniqueTags.flatMap((tag) => {
		const postsWithTag = sortedPosts.filter((post) => post.data.tags.includes(tag));
		return paginate(postsWithTag, {
			pageSize: 10,
			params: { tag },
		});
	});
}

import type { CollectionEntry } from 'astro:content';

export const groupPagesByLang = <T extends CollectionEntry<'docs'>>(pages: T[]) =>
	pages.reduce(
		(pages, page) => {
			const lang = page.id.split('/')[0];
			if (!pages[lang]) pages[lang] = [];
			pages[lang].push(page);
			return pages;
		},
		{} as { [lang: string]: T[] }
	);

