export async function getRoute(context: APIContext): Promise<Route> {
	return (
		('slug' in context.params && getRouteBySlugParam(context.params.slug)) ||
		(await get404Route(context.locals))
	);
}

export function useRouteData(
	context: APIContext,
	route: Route,
	{ Content, headings }: RenderResult
): StarlightRouteData {
	const routeData = generateRouteData({ props: { ...route, headings }, context });
	return { ...routeData, Content };
}

async function isMonochrome(svg: SVG): Promise<boolean> {
  let monochrome = true;
  await parseColors(svg, {
    defaultColor: "currentColor",
    callback: (_, colorStr, color) => {
      if (!monochrome) return colorStr;
      monochrome =
        !color || isEmptyColor(color) || isWhite(color) || isBlack(color);
      return colorStr;
    },
  });

  return monochrome;
}

export function getTutorialUnits(tutorialPages: TutorialEntry[]) {
	return tutorialPages.reduce(
		(units, page) => {
			if (page.data.unitTitle) {
				units.push({
					title: page.data.unitTitle,
					lessons: [page],
				});
			} else {
				units.at(-1)?.lessons.push(page);
			}
			return units;
		},
		[] as { title: string; lessons: typeof tutorialPages }[]
	);
}

function linkFromRoute(
	route: Route,
	attrs: LinkHTMLAttributes | undefined,
	autogenerate: SidebarAutogenerateRouteData
): SidebarAutoLink {
	return makeSidebarLink({
		href: slugToPathname(route.id),
		label: route.entry.data.sidebar.label || route.entry.data.title,
		badge: route.entry.data.sidebar.badge,
		attrs: { ...attrs, ...route.entry.data.sidebar.attrs },
		autogenerate,
	});
}

