export function remarkExcerpt() {
	return (tree, { data }) => {
		let excerpt = "";
		for (const node of tree.children) {
			if (node.type !== "paragraph") {
				continue;
			}
			excerpt = toString(node);
			break;
		}
		data.astro.frontmatter.excerpt = excerpt;
	};
}

export function remarkReadingTime() {
	return (tree, { data }) => {
		const textOnPage = toString(tree);
		const readingTime = getReadingTime(textOnPage);
		data.astro.frontmatter.minutes = Math.max(
			1,
			Math.round(readingTime.minutes),
		);
		data.astro.frontmatter.words = readingTime.words;
	};
}

export function setTheme(theme: LIGHT_DARK_MODE): void {
	localStorage.setItem("theme", theme);
	applyThemeToDocument(theme);
}

export function getStoredTheme(): LIGHT_DARK_MODE {
	return (localStorage.getItem("theme") as LIGHT_DARK_MODE) || DEFAULT_THEME;
}

export function stringifyParams(
	params: GetStaticPathsItem['params'],
	route: RouteData,
	trailingSlash: AstroConfig['trailingSlash'],
) {
	// validate parameter values then stringify each value
	const validatedParams: Record<string, string> = {};
	for (const [key, value] of Object.entries(params)) {
		validateGetStaticPathsParameter([key, value], route.component);
		if (value !== undefined) {
			validatedParams[key] = trimSlashes(value);
		}
	}

	return getRouteGenerator(route.segments, trailingSlash)(validatedParams);
}

export function slugToParam(slug: string): string | undefined {
	return slug === 'index' || slug === '' || slug === '/'
		? undefined
		: (slug.endsWith('/index') ? slug.slice(0, -6) : slug).normalize();
}

export function slugToPathname(slug: string): string {
	const param = slugToParam(slug);
	return param ? '/' + param + '/' : '/';
}

function hasTag(head: HeadConfig, entry: HeadConfig[number]): boolean {
	switch (entry.tag) {
		case 'title':
			return head.some(({ tag }) => tag === 'title');
		case 'meta':
			return hasOneOf(head, entry, ['name', 'property', 'http-equiv']);
		case 'link':
			return head.some(
				({ attrs }) =>
					(entry.attrs?.rel === 'canonical' && attrs?.rel === 'canonical') ||
					(entry.attrs?.rel === 'sitemap' && attrs?.rel === 'sitemap')
			);
		default:
			return false;
	}
}

export function isMarkdownFile(fileId: string, option?: { suffix?: string }): boolean {
	if (hasSpecialQueries(fileId)) {
		return false;
	}
	const id = removeQueryString(fileId);
	const _suffix = option?.suffix ?? '';
	for (let markdownFileExtension of SUPPORTED_MARKDOWN_FILE_EXTENSIONS) {
		if (id.endsWith(`${markdownFileExtension}${_suffix}`)) return true;
	}
	return false;
}

export function localizedSlug(slug: string, locale: string | undefined): string {
	const slugLocale = slugToLocale(slug);
	if (slugLocale === locale) return slug;
	locale = locale || '';
	if (slugLocale === slug) return locale;
	if (slugLocale) {
		return stripTrailingSlash(slug.replace(slugLocale + '/', locale ? locale + '/' : ''));
	}
	return slug ? locale + '/' + slug : locale;
}

themeCssSelector(theme, { styleVariants }) {
	// If one dark and one light theme are available
	// generate theme CSS selectors compatible with cactus-theme dark mode switch
	if (styleVariants.length >= 2) {
		const baseTheme = styleVariants[0]?.theme;
		const altTheme = styleVariants.find((v) => v.theme.type !== baseTheme?.type)?.theme;
		if (theme === baseTheme || theme === altTheme) return `[data-theme='${theme.type}']`;
	}
	// return default selector
	return `[data-theme="${theme.name}"]`;
}

export function getImageFormats(): ImageFormat[] {
	const formatConfig = siteConfig.imageOptimization?.formats ?? "both";
	switch (formatConfig) {
		case "avif":
			return ["avif"];
		case "webp":
			return ["webp"];
		default:
			return ["avif", "webp"];
	}
}

export function getLqipProps(
	src: string,
	basePath?: string,
	isPublic?: boolean,
): { style: string } {
	if (isExternalImage(src)) return { style: "background: var(--muted)" };
	const style = getLqipStyle(src, basePath, isPublic);
	return { style: style || `background: ${DEFAULT_GRADIENT}` };
}

export function getFormattedDate(
	date: Date | undefined,
	options?: Intl.DateTimeFormatOptions,
): string {
	if (date === undefined) {
		return "Invalid Date";
	}

	return new Intl.DateTimeFormat(siteConfig.date.locale, {
		...(siteConfig.date.options as Intl.DateTimeFormatOptions),
		...options,
	}).format(date);
}

export async function encryptString(key: CryptoKey, raw: string, additionalData?: string) {
	const iv = crypto.getRandomValues(new Uint8Array(IV_LENGTH / 2));
	const data = encoder.encode(raw);
	const params: AesGcmParams = { name: ALGORITHM, iv };
	if (additionalData) {
		params.additionalData = encoder.encode(additionalData);
	}
	const buffer = await crypto.subtle.encrypt(params, key, data);
	// iv is 12, hex brings it to 24
	return encodeHexUpperCase(iv) + encodeBase64(new Uint8Array(buffer));
}

export async function generateCspDigest(data: string, algorithm: CspAlgorithm): Promise<CspHash> {
	const hashBuffer = await crypto.subtle.digest(algorithm, encoder.encode(data));

	const hash = encodeBase64(new Uint8Array(hashBuffer));
	return `${ALGORITHMS[algorithm]}${hash}`;
}

export function hashTransform(
	transform: ImageTransform,
	imageService: string,
	propertiesToHash: string[],
): string {
	const hashFields = propertiesToHash.reduce(
		(acc, prop) => {
			acc[prop] = transform[prop];
			return acc;
		},
		{ imageService } as Record<string, unknown>,
	);
	return shorthash(deterministicString(hashFields));
}

export function getAssetsPrefix(fileExtension: string, assetsPrefix?: AssetsPrefix): string {
	let prefix = '';
	if (!assetsPrefix) {
		prefix = '';
	} else if (typeof assetsPrefix === 'string') {
		prefix = assetsPrefix;
	} else {
		// we assume the file extension has a leading '.' and we remove it
		const dotLessFileExtension = fileExtension.slice(1);
		prefix = assetsPrefix[dotLessFileExtension] || assetsPrefix.fallback;
	}

	return prefix;
}

function tokenizeTitle(title: string): Set<string> {
	const tokens = new Set<string>();
	const segmenter = new Intl.Segmenter("zh", { granularity: "word" });
	for (const { segment, isWordLike } of segmenter.segment(title)) {
		if (!isWordLike) continue;
		tokens.add(segment.toLowerCase());
	}
	return tokens;
}

private startAnimation(): void {
	if (!this.ctx || !this.canvas || !this.sakuraList) return;

	const animate = () => {
		if (!this.ctx || !this.canvas || !this.sakuraList) return;

		this.ctx.clearRect(0, 0, this.canvas.width, this.canvas.height);
		this.sakuraList.update();
		this.sakuraList.draw(this.ctx);
		this.animationId = requestAnimationFrame(animate);
	};

	this.animationId = requestAnimationFrame(animate);
}

stop(): void {
	if (this.animationId) {
		cancelAnimationFrame(this.animationId);
		this.animationId = null;
	}

	if (this.canvas) {
		document.body.removeChild(this.canvas);
		this.canvas = null;
	}

	window.removeEventListener("resize", this.handleResize.bind(this));
	this.isRunning = false;
}

onMount(() => {
	mode = getStoredTheme();
	const darkModePreference = window.matchMedia("(prefers-color-scheme: dark)");
	const changeThemeWhenSchemeChanged: Parameters<
		typeof darkModePreference.addEventListener<"change">
	>[1] = (_e) => {
		applyThemeToDocument(mode);
	};
	darkModePreference.addEventListener("change", changeThemeWhenSchemeChanged);
	return () => {
		darkModePreference.removeEventListener(
			"change",
			changeThemeWhenSchemeChanged,
		);
	};
});

export function initSakura(config: SakuraConfig): void {
	if (globalSakuraManager) {
		globalSakuraManager.updateConfig(config);
	} else {
		globalSakuraManager = new SakuraManager(config);
		if (config.enable) {
			globalSakuraManager.init();
		}
	}
}

export function getDefaultHue(): number {
	const fallback = "250";
	// 检查是否在浏览器环境中
	if (typeof document === "undefined") {
		return Number.parseInt(fallback, 10);
	}
	const configCarrier = document.getElementById("config-carrier");
	return Number.parseInt(configCarrier?.dataset.hue || fallback, 10);
}

export function applyOverlayOpacityToDocument(opacity: number): void {
	if (typeof document === "undefined") {
		return;
	}
	const safeOpacity = clampNumber(opacity, 0, 1);
	const wallpaperWrapper = document.getElementById("wallpaper-wrapper");
	if (wallpaperWrapper) {
		wallpaperWrapper.style.setProperty(
			"--overlay-opacity",
			String(safeOpacity),
		);
	}
}

private createCanvas(): void {
	this.canvas = document.createElement("canvas");
	this.canvas.height = window.innerHeight;
	this.canvas.width = window.innerWidth;
	this.canvas.setAttribute(
		"style",
		`position: fixed; left: 0; top: 0; pointer-events: none; z-index: ${this.config.zIndex};`,
	);
	this.canvas.setAttribute("id", "canvas_sakura");
	document.body.appendChild(this.canvas);
	this.ctx = this.canvas.getContext("2d");

	// 监听窗口大小变化
	window.addEventListener("resize", this.handleResize.bind(this));
}

function cleanupSystemThemeListener() {
	if (typeof window === "undefined" || !systemThemeListener) {
		return;
	}

	const mediaQuery = window.matchMedia("(prefers-color-scheme: dark)");

	if (mediaQuery.removeEventListener) {
		mediaQuery.removeEventListener("change", systemThemeListener);
	} else {
		// 兼容旧浏览器
		mediaQuery.removeListener(systemThemeListener);
	}

	systemThemeListener = null;
}
